def gen(rng, size):
    n = max(1, size)
    chars = []
    for i in range(n):
        if i % 2 == 0:
            chars.append(chr(rng.randrange(ord('a'), ord('u') + 1)))
        else:
            chars.append(str(rng.randrange(0, 6)))
    return [''.join(chars)]

