class Solution:
    def replaceDigits(self, s):
        out = list(s)
        for i in range(1, len(s), 2):
            base = out[i - 1]
            steps = int(out[i])
            code = ord(base)
            for _ in range(steps):
                code += 1
            out[i] = chr(code)
        return ''.join(out)

