class Solution:
    def replaceDigits(self, s):
        res = []
        for i, ch in enumerate(s):
            if i % 2 == 0:
                res.append(ch)
            else:
                res.append(chr(ord(s[i - 1]) + int(ch)))
        return ''.join(res)

