var replaceDigits = function(s) {
    let res = '';
    for (let i = 0; i < s.length; i++) {
        if (i % 2 === 0) {
            res += s[i];
        } else {
            res += String.fromCharCode(s.charCodeAt(i - 1) + Number(s[i]));
        }
    }
    return res;
};
